package com.example.secondphone.entity;import jakarta.persistence.AttributeConverter;import jakarta.persistence.Converter;@Converter public class MemberStatusConverter implements AttributeConverter<MemberStatus,String>{public String convertToDatabaseColumn(MemberStatus status){return status==null?null:status.name();}public MemberStatus convertToEntityAttribute(String value){if(value==null)return MemberStatus.ACTIVE;return "INACTIVE".equalsIgnoreCase(value)?MemberStatus.DISABLED:MemberStatus.valueOf(value.toUpperCase());}}
